import React from 'react';
import { Line, Pie, Radar, Bar } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend,
  Filler,
  ArcElement,
  RadialLinearScale
} from 'chart.js';

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend,
  Filler,
  ArcElement,
  RadialLinearScale
);

const DashboardView = ({ transactions }) => {
  const stats = [
    { label: 'TOTAL TRANSACTIONS', value: (9060 + transactions.length).toLocaleString(), delta: '+12.3%', icon: '📈', color: '#10b981' },
    { label: 'FRAUD DETECTED', value: (83 + transactions.filter(t => t.status !== 'approved').length).toString(), delta: '-8.1%', icon: '🛡️', color: '#ef4444' },
    { label: 'BLOCKED', value: (47 + transactions.filter(t => t.status === 'blocked').length).toString(), delta: '+2.4%', icon: '🚫', color: '#3b82f6' }
  ];

  // 1. Transaction Status Pie Chart
  const pieData = {
    labels: ['Approved', 'Flagged', 'Blocked'],
    datasets: [{
      data: [85, 10, 5],
      backgroundColor: ['#10b981', '#f59e0b', '#ef4444'],
      borderWidth: 0
    }]
  };

  // 2. Risk Factor Radar Chart
  const radarData = {
    labels: ['Amount', 'Velocity', 'Location', 'Merchant', 'Time', 'Device'],
    datasets: [{
      label: 'System Risk Metrics',
      data: [65, 59, 90, 81, 56, 55],
      fill: true,
      backgroundColor: 'rgba(16, 185, 129, 0.2)',
      borderColor: '#10b981',
      pointBackgroundColor: '#10b981',
    }]
  };

  // 3. Hourly Volume Line Chart
  const lineData = {
    labels: ['00:00', '04:00', '08:00', '12:00', '16:00', '20:00'],
    datasets: [{
      label: 'Volume',
      data: [400, 200, 700, 1400, 1100, 500],
      borderColor: '#3b82f6',
      backgroundColor: 'rgba(59, 130, 246, 0.1)',
      fill: true,
      tension: 0.4
    }]
  };

  // 4. Fraud by Merchant Bar Chart
  const barData = {
    labels: ['Amazon', 'Apple', 'Netflix', 'Starbucks', 'Uber'],
    datasets: [{
      label: 'Fraud Attempts',
      data: [12, 19, 3, 5, 2],
      backgroundColor: '#f59e0b',
      borderRadius: 5
    }]
  };

  return (
    <div style={{ padding: '2rem' }}>
      <div style={{ marginBottom: '1.5rem' }}>
        <h2 style={{ fontSize: '1.5rem', fontWeight: 'bold', marginBottom: '0.25rem' }}>Fraud Monitoring Dashboard</h2>
        <p style={{ color: '#94a3b8' }}>Real-time overview of transaction activity and threat detection</p>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '1.5rem', marginBottom: '2rem' }}>
        {stats.map(stat => (
          <div key={stat.label} style={{ backgroundColor: '#1e293b', padding: '1.5rem', borderRadius: '1rem', border: '1px solid #334155' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1rem' }}>
              <p style={{ fontSize: '0.75rem', fontWeight: 'bold', color: '#94a3b8', letterSpacing: '0.05em' }}>{stat.label}</p>
              <span style={{ fontSize: '1.25rem' }}>{stat.icon}</span>
            </div>
            <h3 style={{ fontSize: '2rem', fontWeight: 'bold', marginBottom: '0.5rem' }}>{stat.value}</h3>
            <p style={{ fontSize: '0.875rem', color: stat.delta.startsWith('+') ? '#10b981' : '#ef4444' }}>{stat.delta} vs last period</p>
          </div>
        ))}
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem', marginBottom: '1.5rem' }}>
        <div style={{ backgroundColor: '#1e293b', padding: '1.5rem', borderRadius: '1rem', border: '1px solid #334155' }}>
          <h3 style={{ fontSize: '1rem', fontWeight: 'bold', marginBottom: '1.5rem' }}>Risk Radar</h3>
          <div style={{ height: '300px' }}>
             <Radar data={radarData} options={{ maintainAspectRatio: false, scales: { r: { grid: { color: '#334155' }, angleLines: { color: '#334155' }, pointLabels: { color: '#94a3b8' }, ticks: { display: false } } } }} />
          </div>
        </div>
        <div style={{ backgroundColor: '#1e293b', padding: '1.5rem', borderRadius: '1rem', border: '1px solid #334155' }}>
          <h3 style={{ fontSize: '1rem', fontWeight: 'bold', marginBottom: '1.5rem' }}>Transaction Volume</h3>
          <div style={{ height: '300px' }}>
            <Line data={lineData} options={{ maintainAspectRatio: false, plugins: { legend: { display: false } }, scales: { x: { grid: { display: false }, ticks: { color: '#64748b' } }, y: { grid: { color: '#334155' }, ticks: { color: '#64748b' } } } }} />
          </div>
        </div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem' }}>
        <div style={{ backgroundColor: '#1e293b', padding: '1.5rem', borderRadius: '1rem', border: '1px solid #334155' }}>
          <h3 style={{ fontSize: '1rem', fontWeight: 'bold', marginBottom: '1.5rem' }}>Status Distribution</h3>
          <div style={{ height: '250px' }}>
            <Pie data={pieData} options={{ maintainAspectRatio: false, plugins: { legend: { position: 'right', labels: { color: '#94a3b8' } } } }} />
          </div>
        </div>
        <div style={{ backgroundColor: '#1e293b', padding: '1.5rem', borderRadius: '1rem', border: '1px solid #334155' }}>
          <h3 style={{ fontSize: '1rem', fontWeight: 'bold', marginBottom: '1.5rem' }}>Top Fraud Targets</h3>
          <div style={{ height: '250px' }}>
            <Bar data={barData} options={{ maintainAspectRatio: false, plugins: { legend: { display: false } }, scales: { x: { grid: { display: false }, ticks: { color: '#64748b' } }, y: { grid: { color: '#334155' }, ticks: { color: '#64748b' } } } }} />
          </div>
        </div>
      </div>
    </div>
  );
};

export default DashboardView;
